/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Lista de Cadastro de Produtos"
//Report Template Source Header &AppName = "DVelop Software Solutions" &Phone = !"+1 550 8923" &Mail = !"info@mail.com" &Website = !"http://www.web.com" &AddressLine1 = !"French Boulevard 2859" &AddressLine2 = !"Downtown" &AddressLine3 = !"Paris, France" Print printTitle End Footer &PageInfo = "Page: " + &Page.ToString().Trim() &DateInfo = "Date: " + &Today.ToFormattedString() Print printFooter End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
RetornaConfSistema.Call(&Context.EmPCod, &Context.FilCod, domConfSistema.TCon065_BloquearAlteracaoCodigo, &TCon065_BloquearAlteracaoCodigo)
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &ProNom.IsEmpty() print printBlockFilterProNom EndIf If not &ProRef.IsEmpty() print printBlockFilterProRef EndIf If not &ProSts.IsEmpty() &FilterProStsValueDescription = &ProSts.EnumerationDescription()
print printBlockFilterProSts EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'PROBAR' &ProBar1.FromString(&GridStateDynamicFilter.Value) If not &ProBar1.IsEmpty() &ProBar = &ProBar1 print printBlockFilterProBar EndIf Case &DynamicFiltersSelector1 = !'NCMCOD' &NcmCod1.FromString(&GridStateDynamicFilter.Value) If not &NcmCod1.IsEmpty() &NcmCod = &NcmCod1 print printBlockFilterNcmCod EndIf Case &DynamicFiltersSelector1 = !'MARCOD' &MarCod1.FromString(&GridStateDynamicFilter.Value) If not &MarCod1.IsEmpty() &MarCod = &MarCod1 print printBlockFilterMarCod EndIf Case &DynamicFiltersSelector1 = !'MARNOM' &MarNom1.FromString(&GridStateDynamicFilter.Value) If not &MarNom1.IsEmpty() &MarNom = &MarNom1 print printBlockFilterMarNom EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'PROBAR' &ProBar2.FromString(&GridStateDynamicFilter.Value) If not &ProBar2.IsEmpty() &ProBar = &ProBar2 print printBlockFilterProBar EndIf Case &DynamicFiltersSelector2 = !'NCMCOD' &NcmCod2.FromString(&GridStateDynamicFilter.Value) If not &NcmCod2.IsEmpty() &NcmCod = &NcmCod2 print printBlockFilterNcmCod EndIf Case &DynamicFiltersSelector2 = !'MARCOD' &MarCod2.FromString(&GridStateDynamicFilter.Value) If not &MarCod2.IsEmpty() &MarCod = &MarCod2 print printBlockFilterMarCod EndIf Case &DynamicFiltersSelector2 = !'MARNOM' &MarNom2.FromString(&GridStateDynamicFilter.Value) If not &MarNom2.IsEmpty() &MarNom = &MarNom2 print printBlockFilterMarNom EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'PROBAR' &ProBar3.FromString(&GridStateDynamicFilter.Value) If not &ProBar3.IsEmpty() &ProBar = &ProBar3 print printBlockFilterProBar EndIf Case &DynamicFiltersSelector3 = !'NCMCOD' &NcmCod3.FromString(&GridStateDynamicFilter.Value) If not &NcmCod3.IsEmpty() &NcmCod = &NcmCod3 print printBlockFilterNcmCod EndIf Case &DynamicFiltersSelector3 = !'MARCOD' &MarCod3.FromString(&GridStateDynamicFilter.Value) If not &MarCod3.IsEmpty() &MarCod = &MarCod3 print printBlockFilterMarCod EndIf Case &DynamicFiltersSelector3 = !'MARNOM' &MarNom3.FromString(&GridStateDynamicFilter.Value) If not &MarNom3.IsEmpty() &MarNom = &MarNom3 print printBlockFilterMarNom EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod ProNom when &OrderedBy = 1 order EmpCod ProRefPadL when &OrderedBy = 2 order ProRef when &OrderedBy = 3 AND &OrderedDsc = False order (ProRef) when &OrderedBy = 3 AND &OrderedDsc = True order ProEmbUnd when &OrderedBy = 4 AND &OrderedDsc = False order (ProEmbUnd) when &OrderedBy = 4 AND &OrderedDsc = True order NcmCod when &OrderedBy = 5 AND &OrderedDsc = False order (NcmCod) when &OrderedBy = 5 AND &OrderedDsc = True order ProSts when &OrderedBy = 6 AND &OrderedDsc = False order (ProSts) when &OrderedBy = 6 AND &OrderedDsc = True order MarNom when &OrderedBy = 7 AND &OrderedDsc = False order (MarNom) when &OrderedBy = 7 AND &OrderedDsc = True order ProBar when &OrderedBy = 8 AND &OrderedDsc = False order (ProBar) when &OrderedBy = 8 AND &OrderedDsc = True
using DSWWimpProduto(&ProNom, &ProRef, &ProSts, &DynamicFiltersSelector1, &ProBar1, &NcmCod1 , &MarCod1, &MarNom1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &ProBar2, &NcmCod2 , &MarCod2, &MarNom2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &ProBar3, &NcmCod3 , &MarCod3, &MarNom3) &ProStsDescription = ProSts.EnumerationDescription()
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"WWimpProdutoGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"WWimpProdutoGridState")) Else &GridState.FromXml(&Session.Get(!"WWimpProdutoGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PRONOM" &ProNom.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROREF" &ProRef.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PROSTS" &ProSts.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
